import{_ as e,o as t,c as a,ag as i}from"./chunks/framework.CHQlKclR.js";const m=JSON.parse('{"title":"Path Following & Advanced Algorithms","description":"","frontmatter":{},"headers":[],"relativePath":"api/path-following.md","filePath":"api/path-following.md"}'),d={name:"api/path-following.md"};function r(s,o,n,p,l,h){return t(),a("div",null,[...o[0]||(o[0]=[i('<h1 id="path-following-advanced-algorithms" tabindex="-1">Path Following &amp; Advanced Algorithms <a class="header-anchor" href="#path-following-advanced-algorithms" aria-label="Permalink to &quot;Path Following &amp; Advanced Algorithms&quot;">​</a></h1><p>Vortex features state-of-the-art motion algorithms for smooth, high-speed autonomous traversal. These methods leverage odometry to follow pre-computed paths or dynamically generate arcs.</p><h2 id="pure-pursuit" tabindex="-1">Pure Pursuit <a class="header-anchor" href="#pure-pursuit" aria-label="Permalink to &quot;Pure Pursuit&quot;">​</a></h2><p>Pure Pursuit is an algorithm that computes a &quot;look-ahead&quot; point on a path and steers the robot toward it, resulting in natural, high-speed curves.</p><h3 id="pid-odom-pp-set" tabindex="-1"><code>pid_odom_pp_set</code> <a class="header-anchor" href="#pid-odom-pp-set" aria-label="Permalink to &quot;`pid_odom_pp_set`&quot;">​</a></h3><p>Follows a vector of <code>odom</code> points using standard Pure Pursuit.</p><ul><li><code>std::vector&lt;odom&gt; path</code>: The list of points to follow.</li><li><code>bool slew_on</code> (optional): Enables/disables acceleration ramping.</li></ul><h3 id="pid-odom-injected-pp-set" tabindex="-1"><code>pid_odom_injected_pp_set</code> <a class="header-anchor" href="#pid-odom-injected-pp-set" aria-label="Permalink to &quot;`pid_odom_injected_pp_set`&quot;">​</a></h3><p>Automatically &quot;injects&quot; extra points into your path to ensure the robot never gets too far from the line. Recommended for sparse paths.</p><h3 id="pid-odom-smooth-pp-set" tabindex="-1"><code>pid_odom_smooth_pp_set</code> <a class="header-anchor" href="#pid-odom-smooth-pp-set" aria-label="Permalink to &quot;`pid_odom_smooth_pp_set`&quot;">​</a></h3><p>Generates a smooth, curved path from a series of &quot;waypoint&quot; poses. Perfect for going around obstacles without stopping.</p><hr><h2 id="boomerang" tabindex="-1">Boomerang <a class="header-anchor" href="#boomerang" aria-label="Permalink to &quot;Boomerang&quot;">​</a></h2><p>The Boomerang algorithm allows the robot to reach a target pose with a specific heading, following a &quot;boomerang-like&quot; arc.</p><h3 id="pid-odom-boomerang-set" tabindex="-1"><code>pid_odom_boomerang_set</code> <a class="header-anchor" href="#pid-odom-boomerang-set" aria-label="Permalink to &quot;`pid_odom_boomerang_set`&quot;">​</a></h3><p>Starts a Boomerang motion to a single <code>odom</code> target.</p><ul><li><code>odom target</code>: Target {x, y, theta}.</li><li><code>bool slew_on</code> (optional): Enables/disables slew.</li></ul><hr><h2 id="point-to-point-ptp" tabindex="-1">Point-to-Point (PTP) <a class="header-anchor" href="#point-to-point-ptp" aria-label="Permalink to &quot;Point-to-Point (PTP)&quot;">​</a></h2><p>Simpler coordinate-based movements for when you don&#39;t need complex paths.</p><h3 id="pid-odom-set" tabindex="-1"><code>pid_odom_set</code> <a class="header-anchor" href="#pid-odom-set" aria-label="Permalink to &quot;`pid_odom_set`&quot;">​</a></h3><p>Moves the robot directly to a coordinate. If a target heading (theta) is provided, it will automatically use the <strong>Boomerang</strong> algorithm.</p><h3 id="pid-odom-ptp-set" tabindex="-1"><code>pid_odom_ptp_set</code> <a class="header-anchor" href="#pid-odom-ptp-set" aria-label="Permalink to &quot;`pid_odom_ptp_set`&quot;">​</a></h3><p>A strict, linear point-to-point motion. The robot will drive straight to the target {x, y} coordinate without considering its final heading.</p><h3 id="pid-odom-turn-then-drive-set" tabindex="-1"><code>pid_odom_turn_then_drive_set</code> <a class="header-anchor" href="#pid-odom-turn-then-drive-set" aria-label="Permalink to &quot;`pid_odom_turn_then_drive_set`&quot;">​</a></h3><p>A &quot;turn-then-drive&quot; routine where the robot first faces the target point perfectly, then drives to it. Use this for high precision in tight spaces.</p><hr><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="odom-look-ahead-set-double-distance" tabindex="-1"><code>odom_look_ahead_set(double distance)</code> <a class="header-anchor" href="#odom-look-ahead-set-double-distance" aria-label="Permalink to &quot;`odom_look_ahead_set(double distance)`&quot;">​</a></h3><p>Sets the &quot;look-ahead&quot; distance for Pure Pursuit. A larger distance creates smoother arcs but may cut corners. (Default is <code>7.0</code> inches).</p><h3 id="odom-path-spacing-set-double-spacing" tabindex="-1"><code>odom_path_spacing_set(double spacing)</code> <a class="header-anchor" href="#odom-path-spacing-set-double-spacing" aria-label="Permalink to &quot;`odom_path_spacing_set(double spacing)`&quot;">​</a></h3><p>Sets the density of points injected during <code>injected_pp_set</code>. (Default is <code>0.5</code> inches).</p>',32)])])}const u=e(d,[["render",r]]);export{m as __pageData,u as default};
